// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

contract TimeLockedWallet {
    address public immutable beneficiary;
    uint256 public immutable unlockTime;

    event Deposit(address indexed from, uint256 amount);
    event Withdrawal(address indexed to, uint256 amount);

    bool private locked;

    modifier onlyBeneficiary() {
        require(msg.sender == beneficiary, "Only beneficiary can withdraw");
        _;
    }

    modifier nonReentrant() {
        require(!locked, "ReentrancyGuard: reentrant call");
        locked = true;
        _;
        locked = false;
    }

    constructor(address _beneficiary, uint256 _unlockTime) {
        require(_beneficiary != address(0), "Beneficiary cannot be zero address");
        require(_unlockTime > block.timestamp, "Unlock time must be in the future");
        beneficiary = _beneficiary;
        unlockTime = _unlockTime;
    }

    receive() external payable {
        emit Deposit(msg.sender, msg.value);
    }

    function withdraw() external onlyBeneficiary nonReentrant {
        require(block.timestamp >= unlockTime, "Withdrawal locked until unlock time");
        uint256 amount = address(this).balance;
        require(amount > 0, "No funds to withdraw");
        (bool success, ) = beneficiary.call{value: amount}("");
        require(success, "Transfer failed");
        emit Withdrawal(beneficiary, amount);
    }
}

